    name: "Patrick",
    faveFood: "pizza",

    // WRONG: Using 'this' inside an arrow function
    eat: () => {
        // Output: "undefined is eating undefined" (refers to Window object)
        console.log(`${this.name} is eating ${this.faveFood}`);
    }
};

person1.sayHello();
person1.eat();
person2.eat(); 

